        hasher.combine(frequencyPenalty)
        hasher.combine(presencePenalty)
        hasher.combine(stopSequences)
        hasher.combine(thinkingLevel)
        hasher.combine(mediaResolution)
        hasher.combine(repeatPenalty)
    }
