        var seq = [RoutingRuleConfig]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeRoutingRuleConfig.read(from: &buf))
        }
        return seq
    }
}

